"use client";
import * as React from "react";
import { motion, HTMLMotionProps } from "motion/react";
import { cn } from "@/lib/utils";
import { useScaleIn } from "@/lib/use-scale-in";
export interface CardScaleInProps extends HTMLMotionProps<"div"> {
  duration?: number;
  delay?: number;
  initialScale?: number;
}
export function CardScaleIn({
  children,
  className,
  duration = 0.5,
  delay = 0,
  initialScale = 0.8,
  ...props
}: CardScaleInProps) {
  const scaleProps = useScaleIn({
    duration,
    delay,
    from: initialScale,
  });
  return (
    <motion.div {...scaleProps} className={cn(className)} {...props}>
      {children}
    </motion.div>
  );
}

import { type MotionProps, type Easing } from "motion/react";

export interface UseScaleInOptions {
  duration?: number;

  delay?: number;

  from?: number;

  to?: number;

  initialOpacity?: number;

  ease?: Easing | Easing[];

  viewport?: "once" | "always";
}

export function useScaleIn(options: UseScaleInOptions = {}): MotionProps {
  const {
    duration = 0.5,
    delay = 0,
    from = 0.8,
    to = 1,
    initialOpacity = 0,
    ease = "easeOut",
    viewport = "once",
  } = options;

  return {
    initial: {
      scale: from,
      opacity: initialOpacity,
    },
    whileInView: {
      scale: to,
      opacity: 1,
    },
    viewport: {
      once: viewport === "once",
    },
    transition: {
      duration,
      delay,
      ease,
    },
  };
}
